long gcd_helper(long a, long b) {
    while (b != 0) {
        long t = b;
        b = a % b;
        a = t;
    }
    return a < 0 ? -a : a;
}
struct Fraction {
    long num;
    long den;
    Fraction(long n, long d) : num(n), den(d) {}
    void reduce() {
        long g = gcd_helper(num, den);
        num = num / g;
        den = den / g;
    }
    double value() const {
        return (double)num / (double)den;
    }
};

mojo_unit:
def gcd_helper(a_in: Int, b_in: Int) -> Int:
    var a = a_in
    var b = b_in
    while b != 0:
        var t = b
        b = a % b
        a = t
    if a < 0:
        return -a
    return a

struct Fraction(Copyable, Movable):
    var num: Int
    var den: Int

    def __init__(out self, n: Int, d: Int):
        self.num = n
        self.den = d

    def reduce(mut self):
        var g = gcd_helper(self.num, self.den)
        self.num = self.num // g
        self.den = self.den // g

    def value(self) -> Float64:
        return Float64(self.num) / Float64(self.den)

